	store := NewStore(wd)
	def, err := store.ShowDefinition("runtime-only-exec")
	require.NoError(t, err)
	assert.False(t, def.GraphSource, "runtime-managed definition should not report GraphSource")
	assert.Equal(t, "runtime-only-exec", def.ID)
}

